-- Seed transaction data for accounts 3953641204 and 1363167468
-- This script will:
-- 1. Insert 80 transactions for each account (incoming and outgoing)
-- 2. Calculate and update the account balances

BEGIN;

-- ====================================
-- ACCOUNT 3953641204 - 80 TRANSACTIONS
-- ====================================

-- Incoming transactions (payee is account 3953641204) - 32 transactions

-- Outgoing transactions (payer is account 3953641204) - 48 transactions

-- Total incoming for 3953641204: 5,287,500 NGN
-- Total outgoing for 3953641204: 4,152,000 NGN
-- Net balance for 3953641204: 1,135,500 NGN


-- ====================================
-- ACCOUNT 1363167468 - 80 TRANSACTIONS
-- ====================================

-- Incoming transactions (payee is account 1363167468) - 32 transactions

-- Outgoing transactions (payer is account 1363167468) - 48 transactions

-- Total incoming for 1363167468: 5,114,700 NGN
-- Total outgoing for 1363167468: 4,156,200 NGN
-- Net balance for 1363167468: 958,500 NGN

-- Update account balances
UPDATE account 
SET balance = '1135500', 
    updated_at = CURRENT_TIMESTAMP 
WHERE account_number = '3953641204';

UPDATE account 
SET balance = '958500', 
    updated_at = CURRENT_TIMESTAMP 
WHERE account_number = '1363167468';

COMMIT;

-- Verification queries
SELECT 
    '3953641204' as account,
    COUNT(*) as total_transactions,
    COUNT(CASE WHEN payer_account_number = '3953641204' THEN 1 END) as outgoing,
    COUNT(CASE WHEN payee_account_number = '3953641204' THEN 1 END) as incoming,
    SUM(CASE WHEN payee_account_number = '3953641204' THEN CAST(amount AS BIGINT) ELSE 0 END) as total_incoming,
    SUM(CASE WHEN payer_account_number = '3953641204' THEN CAST(amount AS BIGINT) ELSE 0 END) as total_outgoing
FROM transaction 
WHERE tenant_id = 'bpmgd' 
AND (payer_account_number = '3953641204' OR payee_account_number = '3953641204')

UNION ALL

SELECT 
    '1363167468' as account,
    COUNT(*) as total_transactions,
    COUNT(CASE WHEN payer_account_number = '1363167468' THEN 1 END) as outgoing,
    COUNT(CASE WHEN payee_account_number = '1363167468' THEN 1 END) as incoming,
    SUM(CASE WHEN payee_account_number = '1363167468' THEN CAST(amount AS BIGINT) ELSE 0 END) as total_incoming,
    SUM(CASE WHEN payer_account_number = '1363167468' THEN CAST(amount AS BIGINT) ELSE 0 END) as total_outgoing
FROM transaction 
WHERE tenant_id = 'bpmgd' 
AND (payer_account_number = '1363167468' OR payee_account_number = '1363167468');

-- Check updated account balances
SELECT account_number, balance, updated_at 
FROM account 
WHERE account_number IN ('3953641204', '1363167468')
ORDER BY account_number;
